{
  "query": "query getUserProfile($username: String!) { matchedUser(username: $username) { username profile { ranking userAvatar realName reputation } submitStats: submitStatsGlobal { acSubmissionNum { difficulty count submissions } totalSubmissionNum { difficulty count submissions } } badges { id name icon creationDate } } }",
  "variables": { "username": "{{username}}" }
}

{
  "query": "query userProfileCalendar($username: String!) { matchedUser(username: $username) { userCalendar { activeYears streak totalActiveDays submissionCalendar } } }",
  "variables": { "username": "{{username}}" }
}

{
  "query": "query recentSubmissions($username: String!, $limit: Int) { recentSubmissionList(username: $username, limit: $limit) { title titleSlug timestamp statusDisplay lang } }",
  "variables": { "username": "{{username}}", "limit": 20 }
}

{
  "query": "query languageStats($username: String!) { matchedUser(username: $username) { languageProblemCount { languageName problemsSolved } } }",
  "variables": { "username": "{{username}}" }
}

{
  "query": "query skillStats($username: String!) { matchedUser(username: $username) { tagProblemCounts { advanced { tagName tagSlug problemsSolved } intermediate { tagName tagSlug problemsSolved } fundamental { tagName tagSlug problemsSolved } } } }",
  "variables": { "username": "{{username}}" }
}
